import { sendMail } from '../mailer'

interface PasswordResetPayload {
  to: string
  subject: string
  data: {
    reset_url: string
    expires_in: string
  }
}

export async function handlePasswordReset(payload: PasswordResetPayload): Promise<void> {
  const { to, subject, data } = payload

  const html = `
    <!DOCTYPE html>
    <html>
      <head>
        <meta charset="utf-8" />
        <style>
          body { font-family: Arial, sans-serif; background: #f9f9f9; margin: 0; padding: 0; }
          .container { max-width: 520px; margin: 40px auto; background: #fff; border-radius: 8px; padding: 40px; box-shadow: 0 2px 8px rgba(0,0,0,0.08); }
          h1 { font-size: 22px; color: #1a1a1a; margin-bottom: 8px; }
          p { color: #555; line-height: 1.6; }
          .btn { display: inline-block; margin: 24px 0; padding: 12px 28px; background: #2563eb; color: #fff; text-decoration: none; border-radius: 6px; font-weight: bold; }
          .footer { margin-top: 32px; font-size: 12px; color: #999; }
        </style>
      </head>
      <body>
        <div class="container">
          <h1>Reset Your Password</h1>
          <p>We received a request to reset your password. Click the button below to set a new one.</p>
          <a class="btn" href="${data.reset_url}">Reset Password</a>
          <p>This link expires in <strong>${data.expires_in}</strong>. If you did not request a password reset, you can safely ignore this email.</p>
          <div class="footer">
            ThatCookiesMine &mdash; Healthcare Appointment Platform
          </div>
        </div>
      </body>
    </html>
  `

  await sendMail({ to, subject, html })
}

import amqplib, { type Channel, type Connection, type ConsumeMessage } from 'amqplib'
import { handlePasswordReset } from './handlers/password-reset'

const EXCHANGE_NAME = 'notifications'
const QUEUE_NAME = 'notification-service.email'
const ROUTING_KEY = 'email.*'

interface EmailMessage {
  event_type: string
  timestamp: string
  payload: {
    to: string
    subject: string
    data: Record<string, string>
  }
}

async function connect(): Promise<Connection> {
  const host = process.env.RABBITMQ_HOST ?? 'rabbitmq'
  const port = process.env.RABBITMQ_PORT ?? '5672'
  const user = process.env.RABBITMQ_USER ?? 'guest'
  const pass = process.env.RABBITMQ_PASSWORD ?? 'guest'
  const vhost = encodeURIComponent(process.env.RABBITMQ_VHOST ?? '/')

  const url = `amqp://${user}:${pass}@${host}:${port}/${vhost}`
  console.log(`[consumer] Connecting to RabbitMQ at ${host}:${port}...`)
  return amqplib.connect(url)
}

async function dispatch(message: EmailMessage): Promise<void> {
  const { event_type, payload } = message

  switch (event_type) {
    case 'email.password_reset':
      await handlePasswordReset(payload as Parameters<typeof handlePasswordReset>[0])
      break
    default:
      console.warn(`[consumer] Unhandled event_type: ${event_type}`)
  }
}

async function processMessage(channel: Channel, msg: ConsumeMessage): Promise<void> {
  let message: EmailMessage | undefined

  try {
    message = JSON.parse(msg.content.toString()) as EmailMessage
    console.log(`[consumer] Received ${message.event_type} for ${message.payload?.to}`)
    await dispatch(message)
    channel.ack(msg)
  } catch (err) {
    const eventType = message?.event_type ?? 'unknown'
    console.error(`[consumer] Failed to process ${eventType}:`, err)
    // nack without requeue to avoid poison-message loops
    channel.nack(msg, false, false)
  }
}

export async function startConsumer(): Promise<void> {
  const connection = await connect()

  connection.on('error', (err) => {
    console.error('[consumer] Connection error:', err.message)
    process.exit(1)
  })

  connection.on('close', () => {
    console.error('[consumer] Connection closed unexpectedly')
    process.exit(1)
  })

  const channel = await connection.createChannel()
  channel.prefetch(10)

  await channel.assertExchange(EXCHANGE_NAME, 'topic', { durable: true })
  await channel.assertQueue(QUEUE_NAME, { durable: true })
  await channel.bindQueue(QUEUE_NAME, EXCHANGE_NAME, ROUTING_KEY)

  console.log(`[consumer] Listening on queue "${QUEUE_NAME}" (routing: ${ROUTING_KEY})`)

  await channel.consume(QUEUE_NAME, (msg) => {
    if (msg) processMessage(channel, msg)
  })
}

